// Compat : KANTO = juste la région Kanto (utilisé par les anciens modules).
export const KANTO: Species[] = ALL_SPECIES.filter((s) => s.region === 'Kanto');

export const REGIONS: Region[] = ['Kanto', 'Johto', 'Hoenn'];
export const REGION_RANGES: Record<Region, { start: number; end: number; count: number }> = {
  Kanto: { start: 1,   end: 151, count: 151 },
  Johto: { start: 152, end: 251, count: 100 },
  Hoenn: { start: 252, end: 386, count: 135 },
};

export function speciesOfRegion(region: Region): Species[] {
  return ALL_SPECIES.filter((s) => s.region === region);
}
